def perceive(data):
    # Accept a structured payload ({"cvss": 9.1}) or a simple advisory text with
    # a "cvss: <n>" line. Returns only the fields this sensor owns.
    cvss = None
    if isinstance(data, dict):
        cvss = data.get("cvss")
    else:
        for line in str(data).splitlines():
            if ":" in line:
                key, val = line.split(":", 1)
                if key.strip().lower() == "cvss":
                    try:
                        cvss = float(val.strip())
                    except (ValueError, TypeError):
                        cvss = None
    if cvss is None:
        return {}
    try:
        cvss = float(cvss)
    except (ValueError, TypeError):
        return {}
    cvss = max(0.0, min(10.0, cvss))
    if cvss >= 9.0:
        sev = "critical"
    elif cvss >= 7.0:
        sev = "high"
    elif cvss >= 4.0:
        sev = "medium"
    elif cvss > 0.0:
        sev = "low"
    else:
        sev = "none"
    return {"cvss": round(cvss, 1), "severity": sev}
